import { ChatFlow } from 'flowise/dist';

const detectContextLoss = (chatflow: ChatFlow, executionTrace: any[]) => {
  const agentNodes = chatflow.nodes.filter(node => node.type === 'ChatOpenAI' || node.type === 'ConversationalAgent');

  for (let i = 1; i < agentNodes.length; i++) {
    const prevAgentOutput = executionTrace.find(trace => 
      trace.nodeId === agentNodes[i-1].id && trace.type === 'output'
    );
    const currentAgentInput = executionTrace.find(trace => 
      trace.nodeId === agentNodes[i].id && trace.type === 'input'
    );

    if (!currentAgentInput?.input?.includes(prevAgentOutput?.output?.sessionHistory)) {
      return {
        error: 'CONTEXT_LOSS',
        message: `Agent ${agentNodes[i].data.label} missing context from ${agentNodes[i-1].data.label}`
      };
    }
  }
  return null;
};

const validateToolJSON = (toolOutput: any): boolean => {
  try {
    if (typeof toolOutput === 'string') {
      JSON.parse(toolOutput);
    } else if (toolOutput.content) {
      JSON.parse(toolOutput.content);
    }
    return true;
  } catch (e) {
    console.error('Invalid JSON from tool:', toolOutput);
    return false;
  }
};

const monitorToolOutputs = (executionTrace: any[]) => {
  const toolNodes = executionTrace.filter(trace => trace.nodeType === 'CustomTool');
  return toolNodes.some(tool => !validateToolJSON(tool.output));
};

const checkVectorRelevance = (retrievalTrace: any[]) => {
  const lowRelevanceDocs = retrievalTrace.filter(trace => {
    return trace.metadata?.relevanceScore && trace.metadata.relevanceScore < 0.7;
  });

  if (lowRelevanceDocs.length > 0) {
    return {
      error: 'LOW_RELEVANCE_RETRIEVAL',
      docs: lowRelevanceDocs.map(doc => doc.metadata),
      count: lowRelevanceDocs.length
    };
  }
  return null;
};

