    const currentContext = input.output;

    return {
      context: {
        sessionHistory,
        previousOutput: currentContext,
        timestamp: new Date().toISOString()
      }
    };
  }
};

const SafeToolWrapper = (toolNode: any) => {
  return async (...args: any[]) => {
    try {
      const result = await toolNode(...args);

      // Ensure JSON output
      const jsonResult = typeof result === 'string' 
        ? JSON.parse(result)
        : result;

      return {
        success: true,
        data: jsonResult,
        schema: typeof jsonResult === 'object' ? Object.keys(jsonResult) : []
      };
    } catch (error) {
      return {
        success: false,
        error: error.message,
        fallback: {}
      };
    }
  };
};

class SharedMemoryManager {
  private memoryStore = new Map<string, any>();

  async getSessionMemory(sessionId: string) {
    return this.memoryStore.get(sessionId) || { history: [], context: {} };
  }

  async updateSessionMemory(sessionId: string, update: any) {
    const current = await this.getSessionMemory(sessionId);
    this.memoryStore.set(sessionId, {
      ...current,
      history: [...current.history, update],
      context: { ...current.context, ...update.context },
      updatedAt: new Date().toISOString()
    });
  }

  // Use in agent nodes
  const memoryManager = new SharedMemoryManager();
  const sessionMemory = await memoryManager.getSessionMemory(chatflow.sessionId);

