import { Vex } from '@vex_dev/sdk';
import { ChatFlow } from 'flowise/dist';

// Initialize Vex in Flowise server
const vex = new Vex({
  projectId: 'your-project-id',
  apiKey: process.env.VEX_API_KEY!,
});

// Add Vex callback to all chatflows
const flowiseCallbacks = {
  onChatFlowExecutionComplete: async (chatflow: ChatFlow, trace: any) => {
    // Detect coordination failures
    const issues = await vex.detect('multi-agent-coordination', {
      chatflow,
      executionTrace: trace,
      sessionId: chatflow.sessionId
    });

    if (issues.length > 0) {
      await vex.remediate('flowise-agent-failure', {
        issues,
        autoFix: true,
        flowId: chatflow.id
      });
    }
  }
};

// Register with Flowise
export default flowiseCallbacks;
